#include <stdio.h>
#include "userlist.h"

void processUsers(UserList *list) {
    UserList *current = list;

    while (current != NULL) {
        printf("User: %s\n", current->name);
        printf("Email: %s\n", current->email);

        current = current->next;
    }
}

int main(void) {
    UserList *list1 = malloc(sizeof(UserList));

    strcpy(list1->name, "<NAME>");
    strcpy(list1->email, "<EMAIL>");

    list1->next = NULL;

    processUsers(list1);

    return 0;
}